--
-- Disparadores `inscripcion`
--
DELIMITER $$
CREATE TRIGGER `tr_validar_cupo_inscripcion` BEFORE INSERT ON `inscripcion` FOR EACH ROW BEGIN
    DECLARE inscritos INT;
    DECLARE cupo INT;
    DECLARE ya_inscrito INT DEFAULT 0;

    
    SELECT COUNT(*) INTO ya_inscrito
    FROM inscripcion
    WHERE id_usuario = NEW.id_usuario
      AND id_jornada = NEW.id_jornada
      AND estado = 'activa';

    IF ya_inscrito > 0 THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = '?? Ya est?s inscrito en esta jornada.';
    END IF;

    
    SELECT COUNT(*) INTO inscritos
    FROM inscripcion
    WHERE id_jornada = NEW.id_jornada
      AND estado = 'activa';

    
    SELECT cupo_maximo INTO cupo
    FROM jornada
    WHERE id_jornada = NEW.id_jornada;

    
    IF inscritos >= cupo THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = '?? Cupo m?ximo alcanzado para esta jornada.';
    END IF;
END
$$
DELIMITER ;

